 64→    @BeforeEach
 65→    public void createStringKeyValueStore() {
 66→        super.before();
 67→        final StateStoreContext byteStoreContext = byteStoreDriver.context();
 68→        final StoreBuilder<KeyValueStore<Bytes, byte[]>> storeBuilder = Stores.keyValueStoreBuilder(
 69→            Stores.inMemoryKeyValueStore("in-memory-byte-store"),
 70→            new Serdes.BytesSerde(),
 71→            new Serdes.ByteArraySerde());
 72→        byteStore = storeBuilder.build();
 73→        byteStore.init(byteStoreContext, byteStore);
 74→        this.inMemoryKeyValueStore = getInMemoryStore();
 75→    }
