 88→            Stores.inMemoryKeyValueStore("my-store"),
 89→            (Serde<K>) context.keySerde(),
 90→            (Serde<V>) context.valueSerde());
 91→
 92→        final KeyValueStore<K, V> store = storeBuilder.build();
 93→        store.init(context, store);
 94→        return store;
 95→    }
