107→        driver.addEntryToRestoreLog(1, "one");
108→        driver.addEntryToRestoreLog(2, "two");
109→        driver.addEntryToRestoreLog(3, "three");
110→        driver.addEntryToRestoreLog(0, null);
111→
112→        store = createKeyValueStore(driver.context());
113→        context.restore(store.name(), driver.restoredEntries());
114→
115→        assertEquals(3, driver.sizeOf(store));
