121→    @Test
122→    public void shouldReturnKeysWithGivenPrefix() {
123→
124→        final List<KeyValue<Bytes, byte[]>> entries = new ArrayList<>();
125→        entries.add(new KeyValue<>(
126→            new Bytes(stringSerializer.serialize(null, "k1")),
127→            stringSerializer.serialize(null, "a")));
128→        entries.add(new KeyValue<>(
129→            new Bytes(stringSerializer.serialize(null, "prefix_3")),
130→            stringSerializer.serialize(null, "b")));
131→        entries.add(new KeyValue<>(
132→            new Bytes(stringSerializer.serialize(null, "k2")),
133→            stringSerializer.serialize(null, "c")));
134→        entries.add(new KeyValue<>(
135→            new Bytes(stringSerializer.serialize(null, "prefix_2")),
136→            stringSerializer.serialize(null, "d")));
137→        entries.add(new KeyValue<>(
138→            new Bytes(stringSerializer.serialize(null, "k3")),
139→            stringSerializer.serialize(null, "e")));
140→        entries.add(new KeyValue<>(
141→            new Bytes(stringSerializer.serialize(null, "prefix_1")),
142→            stringSerializer.serialize(null, "f")));
143→
144→        byteStore.putAll(entries);
145→        byteStore.commit(Map.of());
146→
147→        final List<String> valuesWithPrefix = new ArrayList<>();
148→        int numberOfKeysReturned = 0;
149→
150→        try (final KeyValueIterator<Bytes, byte[]> keysWithPrefix = byteStore.prefixScan("prefix", stringSerializer)) {
151→            while (keysWithPrefix.hasNext()) {
152→                final KeyValue<Bytes, byte[]> next = keysWithPrefix.next();
153→                valuesWithPrefix.add(new String(next.value));
154→                numberOfKeysReturned++;
155→            }
156→        }
157→
158→        assertThat(numberOfKeysReturned, is(3));
159→        assertThat(valuesWithPrefix.get(0), is("f"));
160→        assertThat(valuesWithPrefix.get(1), is("d"));
161→        assertThat(valuesWithPrefix.get(2), is("b"));
162→    }
