 65→/**
 66→ * A component that provides a {@link #context() StateStoreContext} that can be supplied to a {@link KeyValueStore} so that
 67→ * all entries written to the Kafka topic by the store during {@link KeyValueStore#commit(Map)} are captured for testing purposes.
 68→ * This class simplifies testing of various {@link KeyValueStore} instances, especially those that use
 69→ * {@link MeteredKeyValueStore} to monitor and write its entries to the Kafka topic.
 70→ *
 71→ * <h2>Basic usage</h2>
 72→ * This component can be used to help test a {@link KeyValueStore}'s ability to read and write entries.
 73→ *
 74→ * <pre>
 75→ * // Create the test driver ...
 76→ * KeyValueStoreTestDriver&lt;Integer, String> driver = KeyValueStoreTestDriver.create();
 77→ * KeyValueStore&lt;Integer, String> store = Stores.create("my-store", driver.context())
 78→ *                                              .withIntegerKeys().withStringKeys()
 79→ *                                              .inMemory().build();
 80→ *
 81→ * // Verify that the store reads and writes correctly ...
 82→ * store.put(0, "zero");
 83→ * store.put(1, "one");
 84→ * store.put(2, "two");
 85→ * store.put(4, "four");
 86→ * store.put(5, "five");
 87→ * assertEquals(5, driver.sizeOf(store));
 88→ * assertEquals("zero", store.get(0));
 89→ * assertEquals("one", store.get(1));
 90→ * assertEquals("two", store.get(2));
 91→ * assertEquals("four", store.get(4));
 92→ * assertEquals("five", store.get(5));
 93→ * assertNull(store.get(3));
 94→ * store.delete(5);
 95→ *
 96→ * // Commit the store and verify all current entries were properly committed ...
 97→ * store.commit(Map.of());
 98→ * assertEquals("zero", driver.committedEntryStored(0));
 99→ * assertEquals("one", driver.committedEntryStored(1));
100→ * assertEquals("two", driver.committedEntryStored(2));
101→ * assertEquals("four", driver.committedEntryStored(4));
102→ * assertNull(driver.committedEntryStored(5));
103→ *
104→ * assertEquals(false, driver.committedEntryRemoved(0));
105→ * assertEquals(false, driver.committedEntryRemoved(1));
106→ * assertEquals(false, driver.committedEntryRemoved(2));
107→ * assertEquals(false, driver.committedEntryRemoved(4));
108→ * assertEquals(true, driver.committedEntryRemoved(5));
109→ * </pre>
110→ *
111→ *
112→ * <h2>Restoring a store</h2>
113→ * This component can be used to test whether a {@link KeyValueStore} implementation properly
114→ * {@link StateStoreContext#register(StateStore, StateRestoreCallback) registers itself} with the {@link StateStoreContext}, so that
115→ * the persisted contents of a store are properly restored from the committed entries when the store instance is started.
116→ * <p>
117→ * To do this, create an instance of this driver component, {@link #addEntryToRestoreLog(Object, Object) add entries} that will be
118→ * passed to the store upon creation (simulating the entries that were previously committed to the topic), and then create the store
119→ * using this driver's {@link #context() ProcessorContext}:
120→ *
121→ * <pre>
122→ * // Create the test driver ...
123→ * KeyValueStoreTestDriver&lt;Integer, String> driver = KeyValueStoreTestDriver.create(Integer.class, String.class);
124→ *
125→ * // Add any entries that will be restored to any store that uses the driver's context ...
126→ * driver.addRestoreEntry(0, "zero");
127→ * driver.addRestoreEntry(1, "one");
128→ * driver.addRestoreEntry(2, "two");
129→ * driver.addRestoreEntry(4, "four");
130→ *
131→ * // Create the store, which should register with the context and automatically
132→ * // receive the restore entries ...
133→ * KeyValueStore&lt;Integer, String> store = Stores.create("my-store", driver.context())
134→ *                                              .withIntegerKeys().withStringKeys()
135→ *                                              .inMemory().build();
136→ *
137→ * // Verify that the store's contents were properly restored ...
138→ * assertEquals(0, driver.checkForRestoredEntries(store));
139→ *
140→ * // and there are no other entries ...
141→ * assertEquals(4, driver.sizeOf(store));
142→ * </pre>
143→ *
144→ * @param <K> the type of keys placed in the store
145→ * @param <V> the type of values placed in the store
146→ */
147→public class KeyValueStoreTestDriver<K, V> {
148→
149→    private final Properties props;
150→
151→    /**
152→     * Create a driver object that will have a {@link #context()} that records messages
153→     * {@link ProcessorContext#forward(Record) forwarded} by the store and that provides default serializers and
154→     * deserializers for the given built-in key and value types (e.g., {@code String.class}, {@code Integer.class},
155→     * {@code Long.class}, and {@code byte[].class}). This can be used when store is created to rely upon the
156→     * ProcessorContext's default key and value serializers and deserializers.
157→     *
158→     * @param keyClass   the class for the keys; must be one of {@code String.class}, {@code Integer.class},
159→     *                   {@code Long.class}, or {@code byte[].class}
160→     * @param valueClass the class for the values; must be one of {@code String.class}, {@code Integer.class},
161→     *                   {@code Long.class}, or {@code byte[].class}
162→     * @return the test driver; never null
163→     */
164→    public static <K, V> KeyValueStoreTestDriver<K, V> create(final Class<K> keyClass, final Class<V> valueClass) {
165→        final StateSerdes<K, V> serdes = StateSerdes.withBuiltinTypes("unexpected", keyClass, valueClass);
166→        return new KeyValueStoreTestDriver<>(serdes);
167→    }
168→
169→    /**
170→     * Create a driver object that will have a {@link #context()} that records messages
171→     * {@link ProcessorContext#forward(Record) forwarded} by the store and that provides the specified serializers and
172→     * deserializers. This can be used when store is created to rely upon the ProcessorContext's default key and value serializers
173→     * and deserializers.
174→     *
175→     * @param keySerializer     the key serializer for the {@link StateStoreContext}; may not be null
176→     * @param keyDeserializer   the key deserializer for the {@link StateStoreContext}; may not be null
177→     * @param valueSerializer   the value serializer for the {@link StateStoreContext}; may not be null
178→     * @param valueDeserializer the value deserializer for the {@link StateStoreContext}; may not be null
179→     * @return the test driver; never null
180→     */
181→    public static <K, V> KeyValueStoreTestDriver<K, V> create(final Serializer<K> keySerializer,
182→                                                              final Deserializer<K> keyDeserializer,
183→                                                              final Serializer<V> valueSerializer,
184→                                                              final Deserializer<V> valueDeserializer) {
185→        final StateSerdes<K, V> serdes = new StateSerdes<>(
186→            "unexpected",
187→            Serdes.serdeFrom(keySerializer, keyDeserializer),
188→            Serdes.serdeFrom(valueSerializer, valueDeserializer));
189→        return new KeyValueStoreTestDriver<>(serdes);
190→    }
191→
192→    private final Map<K, V> committedEntries = new HashMap<>();
193→    private final Set<K> committedRemovals = new HashSet<>();
194→    private final List<KeyValue<byte[], byte[]>> restorableEntries = new LinkedList<>();
195→
196→    private final InternalMockProcessorContext<?, ?> context;
197→    private final StateSerdes<K, V> stateSerdes;
198→
199→    @SuppressWarnings("resource")
200→    private KeyValueStoreTestDriver(final StateSerdes<K, V> serdes) {
201→        props = new Properties();
202→        props.put(StreamsConfig.APPLICATION_ID_CONFIG, "application-id");
203→        props.put(StreamsConfig.BOOTSTRAP_SERVERS_CONFIG, "localhost:9092");
204→        props.put(StreamsConfig.DEFAULT_TIMESTAMP_EXTRACTOR_CLASS_CONFIG, MockTimestampExtractor.class);
205→        props.put(StreamsConfig.DEFAULT_KEY_SERDE_CLASS_CONFIG, serdes.keySerde().getClass());
206→        props.put(StreamsConfig.DEFAULT_VALUE_SERDE_CLASS_CONFIG, serdes.valueSerde().getClass());
207→        props.put(StreamsConfig.ROCKSDB_CONFIG_SETTER_CLASS_CONFIG, MockRocksDbConfigSetter.class);
208→        props.put(StreamsConfig.METRICS_RECORDING_LEVEL_CONFIG, "DEBUG");
209→
210→        final ProcessorTopology topology = mock(ProcessorTopology.class);
211→        when(topology.sinkTopics()).thenReturn(Collections.emptySet());
212→
213→        final LogContext logContext = new LogContext("KeyValueStoreTestDriver ");
214→        final RecordCollector recordCollector = new RecordCollectorImpl(
215→            logContext,
216→            new TaskId(0, 0),
217→            new StreamsProducer(
218→                new MockProducer<>(null, true, null, null, null),
219→                AT_LEAST_ONCE,
220→                Time.SYSTEM,
221→                logContext
222→            ),
223→            new DefaultProductionExceptionHandler(),
224→            new MockStreamsMetrics(new Metrics()),
225→            topology
226→        ) {
227→            @Override
228→            public <K1, V1> void send(final String topic,
229→                                      final K1 key,
230→                                      final V1 value,
231→                                      final Headers headers,
232→                                      final Integer partition,
233→                                      final Long timestamp,
234→                                      final Serializer<K1> keySerializer,
235→                                      final Serializer<V1> valueSerializer,
236→                                      final String processorNodeId,
237→                                      final InternalProcessorContext<Void, Void> context) {
238→                // for byte arrays we need to wrap it for comparison
239→
240→                final byte[] keyBytes = keySerializer.serialize(topic, headers, key);
241→                final byte[] valueBytes = valueSerializer.serialize(topic, headers, value);
242→
243→                final K keyTest = serdes.keyFrom(keyBytes);
244→                final V valueTest = serdes.valueFrom(valueBytes);
245→
246→                recordCommitted(keyTest, valueTest);
247→            }
248→
249→            @Override
250→            public <K1, V1> void send(final String topic,
251→                                      final K1 key,
252→                                      final V1 value,
253→                                      final Headers headers,
254→                                      final Long timestamp,
255→                                      final Serializer<K1> keySerializer,
256→                                      final Serializer<V1> valueSerializer,
257→                                      final String processorNodeId,
258→                                      final InternalProcessorContext<Void, Void> context,
259→                                      final StreamPartitioner<? super K1, ? super V1> partitioner) {
260→                throw new UnsupportedOperationException();
261→            }
262→        };
263→
264→        final File stateDir = TestUtils.tempDirectory();
265→        //noinspection ResultOfMethodCallIgnored
266→        stateDir.mkdirs();
267→        stateSerdes = serdes;
268→
269→        context = new InternalMockProcessorContext<>(stateDir, serdes.keySerde(), serdes.valueSerde(), recordCollector, null) {
270→            final ThreadCache cache = new ThreadCache(new LogContext("testCache "), 1024 * 1024L, metrics());
271→
272→            @Override
273→            public ThreadCache cache() {
274→                return cache;
275→            }
276→
277→            @Override
278→            public Map<String, Object> appConfigs() {
279→                return new StreamsConfig(props).originals();
280→            }
281→
282→            @Override
283→            public Map<String, Object> appConfigsWithPrefix(final String prefix) {
284→                return new StreamsConfig(props).originalsWithPrefix(prefix);
285→            }
286→        };
287→    }
288→
289→    private void recordCommitted(final K key, final V value) {
290→        if (value == null) {
291→            // This is a removal ...
292→            committedRemovals.add(key);
293→            committedEntries.remove(key);
294→        } else {
295→            // This is a normal add
296→            committedEntries.put(key, value);
297→            committedRemovals.remove(key);
298→        }
299→    }
300→
301→    /**
302→     * Get the entries that are restored to a KeyValueStore when it is constructed with this driver's {@link #context()
303→     * StateStoreContext}.
304→     *
305→     * @return the restore entries; never null but possibly a null iterator
306→     */
307→    public Iterable<KeyValue<byte[], byte[]>> restoredEntries() {
308→        return restorableEntries;
309→    }
310→
311→    /**
312→     * This method adds an entry to the "restore log" for the {@link KeyValueStore}, and is used <em>only</em> when testing the
313→     * restore functionality of a {@link KeyValueStore} implementation.
314→     * <p>
315→     * To create such a test, create the test driver, call this method one or more times, and then create the
316→     * {@link KeyValueStore}. Your tests can then check whether the store contains the entries from the log.
317→     *
318→     * <pre>
319→     * // Set up the driver and pre-populate the log ...
320→     * KeyValueStoreTestDriver&lt;Integer, String> driver = KeyValueStoreTestDriver.create();
321→     * driver.addRestoreEntry(1,"value1");
322→     * driver.addRestoreEntry(2,"value2");
323→     * driver.addRestoreEntry(3,"value3");
324→     *
325→     * // Create the store using the driver's context ...
326→     * ProcessorContext context = driver.context();
327→     * KeyValueStore&lt;Integer, String> store = ...
328→     *
329→     * // Verify that the store's contents were properly restored from the log ...
330→     * assertEquals(0, driver.checkForRestoredEntries(store));
331→     *
332→     * // and there are no other entries ...
333→     * assertEquals(3, driver.sizeOf(store));
334→     * </pre>
335→     *
336→     * @param key   the key for the entry
337→     * @param value the value for the entry
338→     * @see #checkForRestoredEntries(KeyValueStore)
339→     */
340→    public void addEntryToRestoreLog(final K key, final V value) {
341→        restorableEntries.add(new KeyValue<>(stateSerdes.rawKey(key), stateSerdes.rawValue(value)));
342→    }
343→
344→    /**
345→     * Get the context that should be supplied to a {@link KeyValueStore}'s constructor. This context records any messages
346→     * written by the store to the Kafka topic, making them available via the {@link #committedEntryStored(Object)} and
347→     * {@link #committedEntryRemoved(Object)} methods.
348→     * <p>
349→     * If the {@link KeyValueStore}'s are to be restored upon its startup, be sure to {@link #addEntryToRestoreLog(Object, Object)
350→     * add the restore entries} before creating the store with the {@link StateStoreContext} returned by this method.
351→     *
352→     * @return the processing context; never null
353→     * @see #addEntryToRestoreLog(Object, Object)
354→     */
355→    public StateStoreContext context() {
356→        return context;
357→    }
358→
359→    /**
360→     * Utility method that will count the number of {@link #addEntryToRestoreLog(Object, Object) restore entries} missing from the
361→     * supplied store.
362→     *
363→     * @param store the store that is to have all of the {@link #restoredEntries() restore entries}
364→     * @return the number of restore entries missing from the store, or 0 if all restore entries were found
365→     * @see #addEntryToRestoreLog(Object, Object)
366→     */
367→    public int checkForRestoredEntries(final KeyValueStore<K, V> store) {
368→        int missing = 0;
369→        for (final KeyValue<byte[], byte[]> kv : restorableEntries) {
370→            if (kv != null) {
371→                final V value = store.get(stateSerdes.keyFrom(kv.key));
372→                if (!Objects.equals(value, stateSerdes.valueFrom(kv.value))) {
373→                    ++missing;
374→                }
375→            }
376→        }
377→        return missing;
378→    }
379→
380→    /**
381→     * Utility method to compute the number of entries within the store.
382→     *
383→     * @param store the key value store using this {@link #context() StateStoreContext}.
384→     * @return the number of entries
385→     */
386→    public int sizeOf(final KeyValueStore<K, V> store) {
387→        int size = 0;
388→        try (final KeyValueIterator<K, V> iterator = store.all()) {
389→            while (iterator.hasNext()) {
390→                iterator.next();
391→                ++size;
392→            }
393→        }
394→        return size;
395→    }
396→
397→    /**
398→     * Retrieve the value that the store {@link KeyValueStore#commit(Map) committed} with the given key.
399→     *
400→     * @param key the key
401→     * @return the value that was committed with the key, or {@code null} if no such key was committed or if the entry with this
402→     * key was removed upon commit
403→     */
404→    public V committedEntryStored(final K key) {
405→        return committedEntries.get(key);
406→    }
407→
408→    /**
409→     * Determine whether the store {@link KeyValueStore#commit(Map) committed} the removal of the given key.
410→     *
411→     * @param key the key
412→     * @return {@code true} if the entry with the given key was removed when committed, or {@code false} if the entry was not
413→     * removed when last committed
414→     */
415→    public boolean committedEntryRemoved(final K key) {
416→        return committedRemovals.contains(key);
417→    }
418→
419→    /**
420→     * Return number of removed entry
421→     */
422→    public int numCommittedEntryStored() {
423→        return committedEntries.size();
424→    }
425→
426→    /**
427→     * Return number of removed entry
428→     */
429→    public int numCommittedEntryRemoved() {
430→        return committedRemovals.size();
431→    }
432→
433→    /**
434→     * Remove all {@link #committedEntryStored(Object) committed entries}, {@link #committedEntryRemoved(Object) committed removals},
435→     */
436→    public void clear() {
437→        restorableEntries.clear();
438→        committedEntries.clear();
439→        committedRemovals.clear();
440→    }
441→}
