342→    public <K extends KOut, V extends VOut> void forward(final Record<K, V> record, final String childName) {
343→        if (recordContext != null && record.timestamp() != recordContext.timestamp()) {
344→            setTime(record.timestamp());
345→        }
346→        final ProcessorNode<?, ?, ?, ?> thisNode = currentNode;
347→        try {
348→            for (final ProcessorNode<?, ?, ?, ?> childNode : thisNode.children()) {
349→                currentNode = childNode;
350→                ((ProcessorNode<K, V, ?, ?>) childNode).process(record);
351→            }
352→        } finally {
353→            currentNode = thisNode;
354→        }
355→    }
