362→    @SuppressWarnings("unchecked")
363→    @Override
364→    public void forward(final Object key, final Object value, final To to) {
365→        toInternal.update(to);
366→        if (toInternal.hasTimestamp()) {
367→            setTime(toInternal.timestamp());
368→        }
369→        final ProcessorNode<?, ?, ?, ?> thisNode = currentNode;
370→        try {
371→            for (final ProcessorNode<?, ?, ?, ?> childNode : thisNode.children()) {
372→                if (toInternal.child() == null || toInternal.child().equals(childNode.name())) {
373→                    currentNode = childNode;
374→                    final Record<Object, Object> record = new Record<>(key, value, toInternal.timestamp(), headers());
375→                    ((ProcessorNode<Object, Object, ?, ?>) childNode).process(record);
376→                    toInternal.update(to); // need to reset because MockProcessorContext is shared over multiple
377→                                           // Processors and toInternal might have been modified
378→                }
379→            }
380→        } finally {
381→            currentNode = thisNode;
382→        }
383→    }
